"""Example plugin: export all raw records to context.json."""

import json
from pathlib import Path

from konkon.types import RawDataAccessor, QueryRequest, QueryResult


def schema():
    """Declare query interface."""
    return {
        "description": "Full-text search over raw records exported to JSON",
        "params": {
            "limit": {
                "type": "integer",
                "description": "Maximum number of results to return",
                "default": 100,
            },
        },
        "result": {
            "description": "Matching records as JSON array",
            "metadata_keys": ["total"],
        },
    }


def build(raw_data: RawDataAccessor) -> None:
    """Append all raw records to context.json."""
    records = [
        {
            "id": r.id,
            "content": r.content,
            "meta": r.meta,
            "created_at": str(r.created_at),
        }
        for r in raw_data
    ]
    Path("context.json").write_text(json.dumps(records, indent=2, ensure_ascii=False))


def query(request: QueryRequest) -> str | QueryResult:
    """Search context.json for records whose content matches the query."""
    path = Path("context.json")
    if not path.exists():
        return "No context built yet. Run 'konkon build' first."

    records = json.loads(path.read_text())
    matches = [r for r in records if request.query.lower() in r["content"].lower()]

    if not matches:
        return QueryResult(content=f"No records matching '{request.query}'.")

    return QueryResult(
        content=json.dumps(matches, indent=2, ensure_ascii=False),
        metadata={"total": len(matches)},
    )

"""konkon init — Create a konkon project (system-level, no Bounded Context)."""

import sys
import tomllib
from pathlib import Path

import click

from konkon.application import init as app_init

_VALID_BACKENDS = ("sqlite", "json")


def register(group: click.Group) -> None:
    """Register the init command to the CLI group."""
    group.add_command(init)


@click.command(short_help="Create a konkon project")
@click.argument("directory", default=".", type=click.Path())
@click.option("--force", is_flag=True, help="Overwrite existing plugin file")
@click.option(
    "--plugin",
    default=None,
    help="Plugin template path (relative to DIRECTORY).",
)
@click.option(
    "--raw-backend",
    default=None,
    help="Raw DB backend ('sqlite' or 'json') [default: sqlite]",
)
def init(directory: str, force: bool, plugin: str | None, raw_backend: str | None) -> None:
    """Create a konkon project in the specified directory.

    Generates plugin template and .konkon/ directory.
    Raw DB is NOT created here — it is lazily initialized on first insert.
    """
    if raw_backend is not None and raw_backend not in _VALID_BACKENDS:
        click.echo(
            f"Error: Invalid value for '--raw-backend': "
            f"'{raw_backend}' is not one of {', '.join(repr(b) for b in _VALID_BACKENDS)}.",
            err=True,
        )
        sys.exit(2)
    try:
        app_init(
            Path(directory).resolve(),
            force=force,
            plugin=plugin,
            raw_backend=raw_backend,
        )
    except tomllib.TOMLDecodeError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except TypeError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except ValueError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(2)
    except FileExistsError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(2)
    click.echo(f"Initialized konkon project in {Path(directory).resolve()}", err=True)

"""konkon insert — Append text data to Raw DB (Ingestion Context)."""

import sys
from pathlib import Path

import click

from konkon.application import insert as app_insert
from konkon.core.instance import resolve_project
from konkon.core.models import ConfigError


def register(group: click.Group) -> None:
    """Register the insert command to the CLI group."""
    group.add_command(insert)


def _parse_meta(pairs: tuple[str, ...]) -> dict[str, str] | None:
    """Parse KEY=VALUE pairs into a dict. Returns None if empty."""
    if not pairs:
        return None
    result: dict[str, str] = {}
    for pair in pairs:
        key, _, value = pair.partition("=")
        if not key:
            raise click.BadParameter(f"Invalid meta format: {pair!r}")
        result[key] = value
    return result


@click.command(short_help="Append text data to the Raw DB")
@click.argument("text", required=False, default=None)
@click.option("-m", "--meta", multiple=True, help="Metadata as KEY=VALUE")
@click.pass_context
def insert(ctx: click.Context, text: str | None, meta: tuple[str, ...]) -> None:
    """Append text data to the Raw DB.

    TEXT can be provided as argument or via stdin.
    Delegates to Application Layer Use Case.
    """
    try:
        # Resolve content: argument or stdin
        if text is not None:
            content = text
        elif not sys.stdin.isatty():
            content = sys.stdin.read()
            if not content:
                click.echo("Error: No text provided. Pass TEXT argument or pipe via stdin.", err=True)
                sys.exit(1)
        else:
            click.echo("Error: No text provided. Pass TEXT argument or pipe via stdin.", err=True)
            sys.exit(1)

        # Resolve project root
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)

        # Parse metadata
        meta_dict = _parse_meta(meta)

        # Delegate to Application Layer
        record = app_insert(content, meta_dict, project_root)
        click.echo(record.id)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(1)
    except ConfigError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

"""konkon raw — Raw DB inspection commands (debug / operations)."""

import json
import sys
from pathlib import Path

import click

from konkon.application import raw_get, raw_list
from konkon.core.instance import resolve_project
from konkon.core.models import ConfigError


def register(group: click.Group) -> None:
    """Register the raw command group to the CLI group."""
    group.add_command(raw)


@click.group(short_help="Inspect Raw DB records (debug)")
@click.pass_context
def raw(ctx: click.Context) -> None:
    """Inspect and manage Raw DB records.

    \b
    Subcommands:
      list   List recent raw records
      get    Get a single raw record by ID
    """
    pass


@raw.command("list", short_help="List recent raw records")
@click.option(
    "--limit",
    type=click.IntRange(min=0),
    default=20,
    show_default=True,
    help="Maximum number of records to display.",
)
@click.option(
    "--format",
    "fmt",
    type=click.Choice(["text", "json"]),
    default=None,
    help="Output format (default: auto-detect from TTY).",
)
@click.pass_context
def list_cmd(ctx: click.Context, limit: int, fmt: str | None) -> None:
    """List recent raw records (newest first).

    \b
    Text mode shows a truncated table; JSON mode outputs full records
    as JSON Lines (one JSON object per line).
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(3)

    try:
        records = raw_list(project_root, limit=limit)
    except ConfigError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    if not records:
        return

    # Resolve format: explicit > TTY detection
    if fmt is None:
        fmt = "text" if sys.stdout.isatty() else "json"

    if fmt == "json":
        for r in records:
            obj = {
                "id": r.id,
                "created_at": r.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
                "updated_at": (r.updated_at or r.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
                "content": r.content,
                "meta": dict(r.meta),
            }
            click.echo(json.dumps(obj, ensure_ascii=False))
    else:
        _print_table(records)


@raw.command("get", short_help="Get a single raw record by ID")
@click.argument("record_id", metavar="ID")
@click.option(
    "--format",
    "fmt",
    type=click.Choice(["text", "json"]),
    default=None,
    help="Output format (default: auto-detect from TTY).",
)
@click.pass_context
def get_cmd(ctx: click.Context, record_id: str, fmt: str | None) -> None:
    """Get a single raw record by ID.

    \b
    Text mode shows the full record details;
    JSON mode outputs the record as a single JSON object.
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(3)

    try:
        record = raw_get(project_root, record_id)
    except ConfigError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    if record is None:
        click.echo(f"Error: Record not found: {record_id}", err=True)
        sys.exit(1)

    # Resolve format: explicit > TTY detection
    if fmt is None:
        fmt = "text" if sys.stdout.isatty() else "json"

    if fmt == "json":
        obj = {
            "id": record.id,
            "created_at": record.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
            "updated_at": (record.updated_at or record.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
            "content": record.content,
            "meta": dict(record.meta),
        }
        click.echo(json.dumps(obj, ensure_ascii=False))
    else:
        created = record.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        updated = (record.updated_at or record.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        meta_str = json.dumps(dict(record.meta), ensure_ascii=False) if record.meta else "{}"
        click.echo(f"ID:         {record.id}")
        click.echo(f"Created:    {created}")
        click.echo(f"Updated:    {updated}")
        click.echo(f"Content:    {record.content}")
        click.echo(f"Meta:       {meta_str}")


def _truncate(s: str, length: int = 50) -> str:
    """Truncate string to *length* chars, appending '...' if needed."""
    if len(s) <= length:
        return s
    return s[: length - 3] + "..."


def _print_table(records: list) -> None:
    """Print records as a human-readable table to stdout."""
    # Header
    id_w, ts_w, content_w = 36, 27, 50
    header = f"{'ID':<{id_w}}  {'CREATED_AT':<{ts_w}}  {'UPDATED_AT':<{ts_w}}  {'CONTENT'}"
    click.echo(header)
    click.echo("-" * len(header))

    for r in records:
        created = r.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        updated = (r.updated_at or r.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        content = _truncate(r.content, content_w)
        click.echo(f"{r.id:<{id_w}}  {created:<{ts_w}}  {updated:<{ts_w}}  {content}")

"""konkon search — Run query() from konkon.py (Transformation Context)."""

import sys
from pathlib import Path

import click

from konkon.application import search as app_search
from konkon.core.instance import resolve_project
from konkon.core.models import ConfigError, QueryResult


def register(group: click.Group) -> None:
    """Register the search command to the CLI group."""
    group.add_command(search)


def _parse_param(
    _ctx: click.Context, _param: click.Parameter, value: tuple[str, ...]
) -> dict[str, str]:
    """Parse KEY=VALUE pairs into a dict."""
    result: dict[str, str] = {}
    for item in value:
        if "=" not in item:
            raise click.BadParameter(f"expected KEY=VALUE, got {item!r}")
        key, val = item.split("=", 1)
        result[key] = val
    return result


@click.command(short_help="Search context via query() in konkon.py")
@click.argument("query")
@click.option(
    "-p",
    "--param",
    "params",
    multiple=True,
    callback=_parse_param,
    expose_value=True,
    help="Plugin parameter as KEY=VALUE (repeatable).",
)
@click.pass_context
def search(ctx: click.Context, query: str, params: dict[str, str]) -> None:
    """Run query() in konkon.py and output results.

    Delegates to Application Layer Use Case.
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
        result = app_search(
            project_root,
            query,
            params=params or None,
        )

        if isinstance(result, QueryResult):
            click.echo(result.content)
        else:
            click.echo(result)
    except ConfigError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

"""Ingestion Context facade (01_conceptual_architecture.md §1.1).

Public API for data ingestion. Called by CLI and Serving layers.
Internal implementation delegates to raw_db.py or json_db.py.

Responsibilities:
- Insert a Document into Raw DB as a Raw Record
- Provide RawDataAccessor for Transformation Context (ACL #1)
- Lazy Raw DB initialization (create on first access)
- Backend resolution (SQLite or JSON)

Owns:
- Raw DB (SQLite or JSON), ingest metadata

Does NOT know about:
- AI, vectors, context, plugins, build, query

References:
- 01_conceptual_architecture.md §1.1, §2.1, §3.1
- 03_data_model.md (Raw DB schema)
- json_backend_unified.md §5, §6
- commands/insert.md
"""

import os
import sys
from datetime import datetime
from pathlib import Path

from konkon.core.ingestion.backend import RawDBBackend
from konkon.core.ingestion.json_db import JsonDB
from konkon.core.ingestion.migration import run_migration
from konkon.core.ingestion.raw_db import RawDB
from konkon.core.instance import KONKON_DIR, load_config, raw_db_path
from konkon.core.models import (
    ConfigError,
    DeletedRecord,
    JSONValue,
    RawDataAccessor,
    RawRecord,
)

_JSON_DB_NAME = "raw.json"


def _json_db_path(project_root: Path) -> Path:
    return project_root / KONKON_DIR / _JSON_DB_NAME


def _resolve_backend(project_root: Path) -> tuple[str, bool]:
    """Resolve backend type and whether it was explicitly set.

    Returns (backend, explicitly_set).
    Priority: env > config > auto-detect > 'sqlite' fallback.
    """
    env = os.environ.get("KONKON_RAW_BACKEND")
    if env is not None:
        return env.lower(), True
    config = load_config(project_root)
    if "raw_backend" in config:
        return str(config["raw_backend"]).lower(), True
    # Limited auto-detect: only when env/config are both unset
    db_exists = raw_db_path(project_root).exists()
    json_exists = _json_db_path(project_root).exists()
    if db_exists and json_exists:
        raise ConfigError(
            "Both .konkon/raw.db and .konkon/raw.json exist. "
            "Set 'raw_backend' in .konkon/config.toml to specify "
            "which backend to use."
        )
    if json_exists and not db_exists:
        return "json", False
    return "sqlite", False  # default (includes db-only and neither-exists)


def _check_backend_consistency(
    project_root: Path, backend: str, explicit: bool
) -> None:
    """Warn about mismatch between explicit config and existing files."""
    if not explicit:
        return  # auto-detect handles its own consistency
    db_exists = raw_db_path(project_root).exists()
    json_exists = _json_db_path(project_root).exists()

    if backend == "json" and db_exists and not json_exists:
        print(
            "[WARN] .konkon/raw.db exists but backend is 'json'. "
            "A new raw.json will be created.",
            file=sys.stderr,
        )
    elif backend == "sqlite" and json_exists and not db_exists:
        print(
            "[WARN] .konkon/raw.json exists but backend is 'sqlite'. "
            "A new raw.db will be created.",
            file=sys.stderr,
        )


def _open_db(project_root: Path) -> RawDBBackend:
    """Open (or lazily create) the appropriate Raw DB backend."""
    backend, explicit = _resolve_backend(project_root)
    if backend not in ("sqlite", "json"):
        raise ConfigError(
            f"Unknown backend: {backend!r}. Use 'sqlite' or 'json'."
        )
    _check_backend_consistency(project_root, backend, explicit)
    if backend == "json":
        return JsonDB(_json_db_path(project_root))
    return RawDB(raw_db_path(project_root))


def _db_file_exists(project_root: Path) -> bool:
    """Check if the configured backend's DB file exists."""
    backend, _ = _resolve_backend(project_root)
    if backend not in ("sqlite", "json"):
        raise ConfigError(
            f"Unknown backend: {backend!r}. Use 'sqlite' or 'json'."
        )
    if backend == "json":
        return _json_db_path(project_root).exists()
    return raw_db_path(project_root).exists()


def ingest(
    content: str,
    meta: dict[str, JSONValue] | None,
    project_root: Path,
) -> RawRecord:
    """Ingest a document into Raw DB as a Raw Record.

    Opens (or lazily creates) the Raw DB, delegates to backend.insert(),
    and returns the resulting RawRecord.
    """
    db = _open_db(project_root)
    try:
        return db.insert(content, meta)
    finally:
        db.close()


def update(
    record_id: str,
    content: str | None,
    meta: dict[str, JSONValue] | None,
    project_root: Path,
) -> RawRecord:
    """Update an existing Raw Record's content and/or meta.

    Raises KeyError if record_id is not found.
    """
    db = _open_db(project_root)
    try:
        return db.update(record_id, content=content, meta=meta)
    finally:
        db.close()


def get_record(
    project_root: Path,
    record_id: str,
) -> RawRecord | None:
    """Return a single record by ID, or None if not found.

    Returns None if the Raw DB file does not exist yet
    (read-only command must not create the DB).
    """
    if not _db_file_exists(project_root):
        return None
    db = _open_db(project_root)
    try:
        return db.get_record(record_id)
    finally:
        db.close()


def list_records(
    project_root: Path,
    limit: int = 20,
) -> list[RawRecord]:
    """Return up to *limit* recent records from the Raw DB (newest first).

    Returns an empty list if the Raw DB file does not exist yet
    (read-only command must not create the DB).
    """
    if not _db_file_exists(project_root):
        return []
    db = _open_db(project_root)
    try:
        return db.list_records(limit)
    finally:
        db.close()


def get_accessor(
    project_root: Path,
    modified_since: datetime | None = None,
) -> RawDataAccessor:
    """Return a RawDataAccessor over records in the Raw DB.

    If *modified_since* is given, the accessor is pre-filtered to records
    whose ``updated_at`` is after that timestamp (for incremental builds).
    This keeps the ``modified_since()`` call inside Ingestion Context,
    so Transformation Context never touches a non-Protocol method.

    The Raw DB must already exist (raises if not).
    """
    db = _open_db(project_root)
    accessor = db.accessor()
    if modified_since is not None:
        accessor = accessor.modified_since(modified_since)
    return accessor


def delete(record_id: str, project_root: Path) -> None:
    """Delete a record and create a tombstone.

    Raises KeyError if not found. Does NOT create DB if missing.
    """
    if not _db_file_exists(project_root):
        raise KeyError(f"record not found: {record_id}")
    db = _open_db(project_root)
    try:
        db.delete(record_id)
    finally:
        db.close()


def get_deleted_records_since(
    project_root: Path, since: datetime
) -> list[DeletedRecord]:
    """Return DeletedRecords deleted after timestamp. Empty list if DB missing."""
    if not _db_file_exists(project_root):
        return []
    db = _open_db(project_root)
    try:
        return db.get_deleted_records_since(since)
    finally:
        db.close()


def purge_tombstones(project_root: Path, before: datetime) -> int:
    """Remove old tombstones. Returns 0 if DB missing."""
    if not _db_file_exists(project_root):
        return 0
    db = _open_db(project_root)
    try:
        return db.purge_tombstones(before)
    finally:
        db.close()


def migrate(
    project_root: Path,
    target_backend: str,
    *,
    force: bool = False,
) -> tuple[int, str]:
    """Migrate all records from current backend to target backend.

    Returns (migrated_count, source_backend).
    Raises ConfigError for validation failures.

    Does NOT update config.toml (caller's responsibility).
    """
    # 1. Validate target_backend
    if target_backend not in ("sqlite", "json"):
        raise ConfigError(
            f"Unknown backend: {target_backend!r}. Use 'sqlite' or 'json'."
        )

    # 2. Resolve current backend
    current_backend, _ = _resolve_backend(project_root)
    if current_backend == target_backend:
        raise ConfigError(
            f"Already using {current_backend!r} backend. Nothing to migrate."
        )

    # 3. Validate source exists
    if not _db_file_exists(project_root):
        src_name = "raw.db" if current_backend == "sqlite" else "raw.json"
        raise ConfigError(
            f"Source database .konkon/{src_name} does not exist. "
            f"Nothing to migrate."
        )

    # 4. Validate target does not exist (or --force)
    target_path = (
        _json_db_path(project_root) if target_backend == "json"
        else raw_db_path(project_root)
    )
    if target_path.exists():
        if not force:
            raise FileExistsError(
                f"Target file .konkon/{target_path.name} already exists. "
                f"Use --force to overwrite."
            )
        print(
            f"[WARN] Removing existing .konkon/{target_path.name} (--force)",
            file=sys.stderr,
        )
        target_path.unlink()
        # SQLite WAL mode may leave auxiliary files (03_data_model.md §8)
        if target_backend == "sqlite":
            for suffix in ("-wal", "-shm"):
                aux = target_path.parent / (target_path.name + suffix)
                if aux.exists():
                    aux.unlink()

    # 5. Execute migration
    source = _open_db(project_root)
    try:
        if target_backend == "json":
            target = JsonDB(target_path)
        else:
            target = RawDB(target_path)
        try:
            count = run_migration(source, target, target_backend)
            return count, current_backend
        finally:
            target.close()
    finally:
        source.close()

"""Tests for cli/search.py — konkon search command (Step 10)."""

from pathlib import Path

from click.testing import CliRunner

from konkon.cli import main


def _init_project(runner: CliRunner, path: Path) -> None:
    """Helper: initialize a konkon project."""
    runner.invoke(main, ["init", str(path)])


def _write_plugin(path: Path, code: str) -> None:
    """Helper: overwrite konkon.py with custom plugin code."""
    (path / "konkon.py").write_text(code)


class TestSearchCommand:
    """konkon search QUERY — CLI integration tests."""

    def test_search_returns_result_on_stdout(self, tmp_path: Path):
        """konkon search 'hello' with valid plugin → exit 0, result on stdout."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        _write_plugin(tmp_path, """\
def schema():
    return {"description": "test", "params": {}}

def build(raw_data, context):
    pass

def query(request):
    return "found: " + request.query
""")
        result = runner.invoke(main, ["-C", str(tmp_path), "search", "hello"])
        assert result.exit_code == 0
        assert "found: hello" in result.output

    def test_search_without_init_exit_1(self, tmp_path: Path):
        """konkon search without project init → exit 1."""
        runner = CliRunner()
        result = runner.invoke(main, ["-C", str(tmp_path), "search", "hello"])
