"""konkon describe — Show plugin schema (query interface description)."""

import json
import sys
from pathlib import Path

import click

from konkon.application import describe as app_describe
from konkon.core.instance import resolve_project


def register(group: click.Group) -> None:
    """Register the describe command to the CLI group."""
    group.add_command(describe)


@click.command(short_help="Show plugin schema (query interface)")
@click.option(
    "--format",
    "fmt",
    type=click.Choice(["text", "json"]),
    default=None,
    help="Output format (default: auto-detect from TTY).",
)
@click.option(
    "--plugin",
    type=click.Path(exists=True, dir_okay=False, path_type=Path),
    default=None,
    help="Path to a custom konkon.py plugin.",
)
@click.pass_context
def describe(ctx: click.Context, fmt: str | None, plugin: Path | None) -> None:
    """Show the plugin's query interface (schema).

    \b
    Calls schema() in konkon.py and displays:
    - description, params, result info (text mode)
    - raw schema dict (json mode)
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(3)

    try:
        schema = app_describe(project_root, plugin_override=plugin)
    except (FileNotFoundError, ValueError, SyntaxError, ImportError) as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    # Resolve format: explicit > TTY detection
    if fmt is None:
        fmt = "text" if sys.stdout.isatty() else "json"

    if fmt == "json":
        click.echo(json.dumps(schema, ensure_ascii=False, indent=2))
    else:
        _print_text(schema)


def _print_text(schema: dict) -> None:
    """Print schema in human-readable text format."""
    description = schema.get("description", "")
    if description:
        click.echo(f"Description: {description}")

    params = schema.get("params", {})
    if params:
        click.echo("")
        click.echo("Params:")
        for name, spec in params.items():
            typ = spec.get("type", "")
            desc = spec.get("description", "")
            parts = [f"  {name:<8} {typ:<8} {desc}"]
            extras = []
            if "enum" in spec:
                extras.append(f"enum: {', '.join(str(v) for v in spec['enum'])}")
            if "default" in spec:
                extras.append(f"default: {spec['default']}")
            if extras:
                parts.append(f" ({'; '.join(extras)})")
            click.echo("".join(parts))

    result = schema.get("result")
    if result:
        click.echo("")
        result_desc = result.get("description", "")
        if result_desc:
            click.echo(f"Result: {result_desc}")

"""konkon delete — Delete a Raw Record (Ingestion Context)."""

import sys
from pathlib import Path

import click

from konkon.application import delete as app_delete
from konkon.core.instance import resolve_project
from konkon.core.models import ConfigError


def _is_tty() -> bool:
    """Check if both stdin and stderr are TTY (for confirmation prompt)."""
    return sys.stdin.isatty() and sys.stderr.isatty()


def register(group: click.Group) -> None:
    """Register the delete command to the CLI group."""
    group.add_command(delete_cmd)


@click.command("delete", short_help="Delete a Raw Record by ID")
@click.argument("record_id")
@click.option(
    "--force", "-f",
    is_flag=True,
    default=False,
    help="Skip confirmation prompt.",
)
@click.pass_context
def delete_cmd(
    ctx: click.Context,
    record_id: str,
    force: bool,
) -> None:
    """Delete a Raw Record by ID.

    Physically deletes the record from Raw DB and creates a tombstone
    for the next build. Run 'konkon build' after deleting to update
    the Context Store.

    \b
    Example:
      konkon delete 019516a0-3b40-7f8a-b12c-4e5f6a7b8c9d
      konkon delete --force 019516a0-3b40-7f8a-b12c-4e5f6a7b8c9d
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except (FileNotFoundError, ConfigError) as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    # Confirmation prompt (delete.md §振る舞い step 3)
    if not force:
        if _is_tty():
            click.echo(
                f"Delete record {record_id}? [y/N] ",
                err=True,
                nl=False,
            )
            try:
                answer = input().strip().lower()
            except EOFError:
                sys.exit(0)
            if answer not in ("y", "yes"):
                sys.exit(0)
        # Non-TTY without --force: stdin or stderr is not TTY
        # Per spec: "stdin または stderr が TTY でない場合は --force が暗黙的に適用される"
        # So we proceed without prompting.

    try:
        app_delete(record_id, project_root)
        click.echo(record_id)
        click.echo(
            "[INFO] Record deleted. Run 'konkon build' to update Context Store.",
            err=True,
        )
    except KeyError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)
    except ConfigError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)
